import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle, Package, Zap, ArrowLeft, PartyPopper } from 'lucide-react';

export default function CreateListing() {
  const navigate = useNavigate();
  const [type, setType] = useState('item');
  const [showSuccess, setShowSuccess] = useState(false);

  const handlePublish = (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    
    const newListing = {
      id: Date.now(),
      title: formData.get('title'),
      wtk: formData.get('wtk'),
      location: formData.get('location'),
      type: type,
      date: new Date().toLocaleDateString()
    };

    const existing = JSON.parse(localStorage.getItem('myListings')) || [];
    localStorage.setItem('myListings', JSON.stringify([newListing, ...existing]));

    setShowSuccess(true);
    setTimeout(() => {
      setShowSuccess(false);
      navigate('/dashboard');
    }, 2500);
  };

  return (
    <div className="p-10 max-w-3xl mx-auto space-y-8">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-slate-400 font-bold hover:text-teal-600 transition-all">
        <ArrowLeft size={20} /> Back
      </button>

      <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 shadow-sm border border-slate-50 dark:border-slate-800 space-y-8 transition-colors">
        <div className="flex bg-slate-50 dark:bg-slate-800 p-1.5 rounded-2xl gap-2">
          <button onClick={() => setType('item')} className={`flex-1 py-4 rounded-xl font-bold transition-all ${type === 'item' ? 'bg-white dark:bg-slate-700 text-teal-600 shadow-sm' : 'text-slate-400'}`}>Physical Item</button>
          <button onClick={() => setType('skill')} className={`flex-1 py-4 rounded-xl font-bold transition-all ${type === 'skill' ? 'bg-white dark:bg-slate-700 text-teal-600 shadow-sm' : 'text-slate-400'}`}>Professional Skill</button>
        </div>

        <form onSubmit={handlePublish} className="space-y-6">
          <input name="title" required placeholder="Title" className="w-full p-6 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-2xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold" />
          <div className="grid grid-cols-2 gap-6">
            <input name="wtk" required type="number" placeholder="WTK Value" className="w-full p-6 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-2xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold" />
            <input name="location" required placeholder="Location" className="w-full p-6 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-2xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold" />
          </div>
          <button type="submit" className="w-full bg-teal-600 text-white py-6 rounded-2xl font-black text-lg hover:bg-teal-700 shadow-lg shadow-teal-600/20">Publish Listing</button>
        </form>
      </div>

      <AnimatePresence>
        {showSuccess && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm">
            <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-white dark:bg-slate-900 p-12 rounded-[50px] text-center max-w-sm w-full">
              <PartyPopper size={48} className="text-teal-600 mx-auto mb-4" />
              <h2 className="text-3xl font-black dark:text-white">Published!</h2>
              <div className="mt-6 w-full bg-slate-100 dark:bg-slate-800 h-1 rounded-full overflow-hidden">
                <motion.div initial={{ width: "0%" }} animate={{ width: "100%" }} transition={{ duration: 2 }} className="h-full bg-teal-600" />
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}
